INSERT INTO forum VALUES 
(1,'2026-05-10 08:30:00','新手求助：40cm小缸适合养什么鱼？','<p>各位鱼友好，我是纯新手。上周买了一个40x25x30的超白小缸，配了森森瀑布过滤器和50W加热棒。正在养水第5天。</p><p>请教这个配置适合养什么鱼？喜欢颜色鲜艳好养活的。需要配灯吗？谢谢！</p>',0,'fish_lover_阿强','upload/forum_cover_news1.jpg','开放',0,'2026-05-12 00:00:00','upload/forum_cover_news1.jpg',0,0,11),
(2,'2026-05-11 10:15:00','金龙鱼和红龙鱼哪个更适合新手？','<p>攒了半年的钱终于够买一条龙鱼了！纠结选金龙还是红龙？预算5000以内。</p><p>请教老玩家：1.饲养难度 2.哪个更容易发色 3.水质要求差别 4.60的缸能养吗</p>',0,'龙鱼小白阿杰','upload/forum_cover_news2.jpg','开放',1,'2026-05-13 00:00:00','upload/forum_cover_news2.jpg',0,0,12),
(3,'2026-05-11 14:20:00','【多图】历时半年打造的120cm水草缸','<p>去年11月开始筹备，终于完成！</p><p>设备：120x45x45超白缸、尼特利AT3灯具x2、伊罕600过滤桶、4L二氧化碳钢瓶</p><p>水草：迷你矮珍珠（前景）、血红宫廷（中景）、红蝴蝶（后景）、莫斯树</p><p>生物：宝莲灯x50、大和藻虾x20、小精灵x5</p>',0,'造景达人_小林','upload/forum_cover_news3.jpg','开放',1,'2026-05-13 00:00:00','upload/forum_cover_news3.jpg',0,0,13),
(4,'2026-05-12 09:00:00','孔雀鱼繁殖记录贴——从交配到小鱼满月','<p>养孔雀鱼三年了，专门记录一胎从交配到小鱼的完整过程。</p><p>母鱼：蓝草尾约5cm。怀孕28天。凌晨2:00开始生产持续约4小时。产62条存活58条。</p><p>会持续更新小鱼成长情况...</p>',0,'孔雀鱼专家_老赵','upload/forum_cover_news4.jpg','开放',0,'2026-05-12 00:00:00','upload/forum_cover_news4.jpg',0,0,14),
(5,'2026-05-12 15:30:00','求救！龙鱼掉眼了怎么办？','<p>养了两年的金龙，左眼开始向下倾斜。查资料说光线问题，但用的是顶部灯管。</p><p>目前措施：1.降低水位 2.水面放乒乓球 3.减少夜间光照</p><p>有没有治好掉眼的老铁分享经验？</p>',0,'龙鱼急救中_阿龙','upload/forum_cover_news5.jpg','开放',0,'2026-05-12 00:00:00','upload/forum_cover_news5.jpg',0,0,15),
(6,'2026-05-13 11:00:00','海水缸开缸一个月记录','<p>记录一个月开缸过程。</p><p>设备：红海90cm套缸、BM C7蛋白质分离器、造浪泵x2、AI Prime 16HD灯</p><p>养水：Day1-3空缸循环，Day4加活石活沙，Day7-28爆藻期</p><p>NO3降到安全范围后下了小丑鱼x2+奶嘴海葵，状态不错！</p>',0,'海缸新手_小陈','upload/forum_cover_news6.jpg','开放',1,'2026-05-13 00:00:00','upload/forum_cover_news6.jpg',0,0,16),
(7,'2026-05-13 16:45:00','灯光选择：T5灯管 vs LED灯','<p>准备给120cm龙鱼缸换灯。</p><p>T5方案：喜万年x2+水族之星x2，灯架约600元，一年一换</p><p>LED方案：尼特利AT3x2，约1000元/个，寿命3-5年</p><p>哪个方案更合适？LED对龙鱼发色效果好吗？</p>',0,'纠结的鱼友_大明','upload/forum_cover_news1.jpg','开放',0,'2026-05-13 00:00:00','upload/forum_cover_news1.jpg',0,0,17),
(8,'2026-05-14 08:00:00','罗汉鱼起头经验分享','<p>养罗汉五年，从P级到AAA级。</p><p>关键：1.基因占60% 2.水温28-32度 3.高蛋白饮食 4.互动刺激 5.避免惊吓</p><p>欢迎交流补充！</p>',0,'罗汉鱼玩家_大壮','upload/forum_cover_news2.jpg','开放',0,'2026-05-14 00:00:00','upload/forum_cover_news2.jpg',0,0,18),
(9,'2026-05-14 10:30:00','出差一周鱼怎么办？自动喂鱼器推荐','<p>下月出差一周。缸里是灯鱼+孔雀鱼+鼠鱼，每天喂一次。</p><p>预算200以内，有靠谱的自动喂鱼器推荐吗？</p>',0,'出差焦虑的小王','upload/forum_cover_news3.jpg','开放',0,'2026-05-14 00:00:00','upload/forum_cover_news3.jpg',0,0,19),
(10,'2026-05-14 14:00:00','【活动】成都鱼友线下交流会','<p>时间：2026年6月15日14:00-18:00</p><p>地点：锦江区太古里星巴克</p><p>内容：经验分享、摄影教学、小缸造景比赛、闲置器材交换</p><p>已报名8人，满20人截止。报名请私信或留言。</p>',0,'成都鱼友会长_老李','upload/forum_cover_news4.jpg','开放',1,'2026-05-14 00:00:00','upload/forum_cover_news4.jpg',0,0,20);
INSERT INTO news VALUES 
(1,'2026-05-01 09:00:00','2025观赏鱼流行趋势：龙鱼称王小型鱼崛起','<p>龙鱼以38%市场份额继续领跑。孔雀鱼、灯鱼、斗鱼等小型热带鱼销量同比增长25%。智能鱼缸占比从8%增长到18%。WiFi控温器、自动喂食器成为年轻消费者标配。</p>','upload/news_picture_new1.jpg','观赏鱼资讯编辑部','upload/news_headportrait1.jpg','金龙鱼',NULL),
(2,'2026-05-02 10:00:00','新手养鱼必看：开缸养水完全指南','<p>养鱼先养水。步骤：1.设备准备 2.建立硝化系统（14-21天） 3.水质检测（氨氮=0，亚硝酸盐=0） 4.分批放鱼，每次间隔一周以上。</p>','upload/news_picture_new2.jpg','观赏鱼资讯编辑部','upload/news_headportrait2.jpg',NULL,NULL),
(3,'2026-05-03 11:00:00','热带鱼混养攻略：最适合混养的观赏鱼组合','<p>新手黄金搭配：孔雀鱼+月光鱼+玛丽鱼。中型缸：虎皮鱼群+彩虹鱼。混养黄金法则：1.体型差不超过3倍 2.食性相似 3.活动水层错开 4.性情不冲突 5.水质要求一致。</p>','upload/news_picture_new3.jpg','观赏鱼资讯编辑部','upload/news_headportrait3.jpg','月光鱼',NULL),
(4,'2026-05-05 08:30:00','观赏鱼常见疾病及家庭治疗方法','<p>1.白点病：升温30-32度+甲基蓝 2.烂鳍病：换水50%+黄粉 3.水霉病：隔离+黄粉盐浴 4.肠炎：停食3天+大蒜汁拌食 5.鰓病：大量换水+福尔马林药浴。</p>','upload/news_picture_new4.jpg','观赏鱼资讯编辑部','upload/news_headportrait4.jpg',NULL,NULL),
(5,'2026-05-06 14:00:00','城市白领的新宠：办公桌上的迷你水族世界','<p>越来越多白领在办公桌摆放迷你水族箱。15-30cm微型鱼缸销量增长40%以上。科学研究表明观看鱼缸可有效降低心率和压力荷尔蒙。</p>','upload/news_picture_new5.jpg','观赏鱼资讯编辑部','upload/news_headportrait5.jpg','孔雀鱼',NULL),
(6,'2026-05-08 09:00:00','第十五届中国国际观赏鱼展在上海开幕','<p>来自20多国超500家参展商。世界龙鱼大赛展示200余条精品，总价值超5000万元。国际造景师大赛中国选手获金奖。中国观赏鱼市场规模达478亿元同比增长12%。</p>','upload/news_picture_new6.jpg','观赏鱼资讯编辑部','upload/news_headportrait6.jpg','血红龙鱼',NULL),
(7,'2026-05-09 10:30:00','锦鲤饲养入门：从池塘选址到日常管理','<p>池塘面积6平方米以上，水深1-1.5米。三段式过滤系统。春季逐步增加喂食，夏季投喂高蛋白，秋季增加色扬饲料，冬季停食或少量喂小麦胚芽。</p>','upload/news_picture_new1.jpg','观赏鱼资讯编辑部','upload/news_headportrait7.jpg','锦鲤',NULL),
(8,'2026-05-10 15:00:00','智能鱼缸时代：AI如何改变养鱼方式','<p>智能鱼缸可实现自动喂食（远程控制）、水质实时监测、自动换水、光谱可调LED灯、AI鱼病识别。智能设备不能完全替代人工观察。</p>','upload/news_picture_new2.jpg','观赏鱼资讯编辑部','upload/news_headportrait8.jpg',NULL,NULL),
(9,'2026-05-12 11:00:00','海水观赏鱼入门：小丑鱼与珊瑚礁生态缸','<p>推荐60cm海水套缸起步预算5000-8000元。入门鱼种：小丑鱼、蓝魔雀鲷、黄吊、草莓、虾虎。海水缸最大坑：管不住手密度太大水质崩溃。</p>','upload/news_picture_new3.jpg','观赏鱼资讯编辑部','upload/news_headportrait1.jpg','小丑鱼',NULL),
(10,'2026-05-13 10:00:00','家庭养鱼的五大误区','<p>1.缸越大越好？60-80cm甜蜜点 2.水清=水质好？需用测试剂 3.喂越多越好？2分钟吃完量 4.换水越多越干净？30-50%即可 5.自来水放一天就能用？需困水48小时。</p>','upload/news_picture_new4.jpg','观赏鱼资讯编辑部','upload/news_headportrait2.jpg',NULL,NULL);
